// Step 5 — Pessoas no local + Aceno
function StepAceno({ onNext, onBack }: { onNext: () => void; onBack: () => void }) {
  const [waved, setWaved] = useState<string | null>(null);
  const [accepted, setAccepted] = useState(false);

  return (
    <div className="flex flex-col h-full">
      <div className="px-6 pt-4 pb-2">
        <h2 className="text-xl font-bold text-gray-900">Pessoas no local</h2>
        <p className="text-gray-500 text-sm mt-1">
          Você vê quem está presente agora. Para iniciar uma conversa, envie um <strong>aceno</strong> 👋
        </p>
      </div>

      <div className="flex-1 px-6 overflow-y-auto">
        <div className="flex flex-col gap-3 mt-2">
          {/* Mock home screen */}
          <div className="bg-[#1F3A5F] rounded-2xl p-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-lg">☕</span>
              <div>
                <p className="text-white font-semibold text-xs">Café do Ponto</p>
                <p className="text-white/60 text-[10px] flex items-center gap-1"><Clock size={9} /> 47:22</p>
              </div>
            </div>
            <div className="flex gap-1.5">
              <div className="bg-white/20 text-white text-[10px] px-2 py-1 rounded-lg">↺ Renovar</div>
              <div className="bg-white/20 text-white text-[10px] px-2 py-1 rounded-lg">→ Sair</div>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            {CHARACTERS.map((char) => (
              <div key={char.name} className="bg-white rounded-2xl p-3 shadow-sm border border-gray-100 flex items-center gap-3">
                <Avatar char={char} size="md" showBadge />
                <div className="flex-1">
                  <p className="font-semibold text-gray-800 text-sm">{char.name}, {char.age}</p>
                  <p className="text-xs text-gray-400">Aqui: {char.intention}</p>
                </div>
                {waved === char.name ? (
                  <div className={`text-xs px-3 py-2 rounded-xl font-medium ${accepted && waved === char.name ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                    {accepted && waved === char.name ? '✓ Chat' : 'Aceno enviado'}
                  </div>
                ) : (
                  <button
                    onClick={() => setWaved(char.name)}
                    className="bg-orange-400 text-white text-xs font-semibold px-3 py-2 rounded-xl active:scale-95 transition-transform flex items-center gap-1"
                  >
                    👋 Acenar
                  </button>
                )}
              </div>
            ))}
          </div>

          {waved && !accepted && (
            <div className="bg-orange-50 rounded-2xl p-3 border border-orange-100">
              <p className="text-xs text-orange-700 font-semibold mb-1">Aceno enviado para {waved}!</p>
              <p className="text-xs text-orange-600 mb-2">Agora {waved} recebe uma notificação e pode aceitar ou ignorar. Se aceitar, o chat abre automaticamente.</p>
              <button
                onClick={() => setAccepted(true)}
                className="w-full bg-orange-400 text-white text-xs font-semibold py-2 rounded-xl"
              >
                Simular: {waved} aceitou! 🎉
              </button>
            </div>
          )}

          {accepted && (
            <div className="bg-green-50 rounded-2xl p-3 border border-green-100">
              <p className="text-xs text-green-700 font-semibold mb-1">Chat aberto com {waved}!</p>
              <p className="text-xs text-green-600">A conversa existe apenas enquanto vocês dois estiverem no mesmo local. Ao sair, o chat é encerrado.</p>
            </div>
          )}
        </div>
      </div>

      <div className="px-6 py-4 flex gap-3">
        <button onClick={onBack} className="flex-1 py-3 rounded-2xl border border-gray-200 text-gray-500 font-medium text-sm">
          Voltar
        </button>
        <button onClick={onNext} className="flex-2 px-6 py-3 rounded-2xl bg-orange-400 text-white font-semibold text-sm flex items-center gap-1">
          Continuar <ChevronRight size={16} />
        </button>
      </div>
    </div>
  );
}

